import pandas as pd
from collections import defaultdict

# Load NYSE stock info
var_name = 'var_functions.query_db:122'
with open(locals()[var_name], 'r') as f:
    nyse_stocks = json.load(f)

# Create symbol to company name mapping
symbol_to_name = {stock['Symbol']: stock['Company Description'] for stock in nyse_stocks}
all_symbols = list(symbol_to_name.keys())

# Function to count up/down days from query results
def count_up_down_days(query_result):
    """Count up days (close > open) and down days (close < open)"""
    if not query_result:
        return None

    up_days = 0
    down_days = 0

    for record in query_result:
        try:
            open_price = float(record['Open'])
            close_price = float(record['Close'])

            if close_price > open_price:
                up_days += 1
            elif close_price < open_price:
                down_days += 1
            # Equal days are not counted as up or down
        except (ValueError, TypeError):
            continue

    return {'up': up_days, 'down': down_days, 'total': up_days + down_days}

print('__RESULT__:')
print(json.dumps({
    'function_ready': True,
    'total_symbols': len(all_symbols)
}))"}

